          padding: 0.55rem 1rem;
          border-radius: 50px;
          font-size: 0.82rem;
          font-weight: 700;
          transition: all 0.3s ease;
          text-decoration: none;
        }
        .project-card-links a:first-child {
          background: linear-gradient(135deg, #fff2d8, #c98545);
          color: #24140f;
          box-shadow: 0 4px 15px rgba(36, 20, 15, 0.2);
        }
        .project-card-links a:first-child:hover {
          transform: translateY(-3px);
          box-shadow: 0 8px 20px rgba(201, 133, 69, 0.3);
        }
        .project-card-links a:nth-child(2) {
          background: rgba(255, 248, 237, 0.08);
          color: #fff8ed;
          border: 1px solid rgba(255, 248, 237, 0.15);
        }
        .project-card-links a:nth-child(2):hover {
          background: #f6ead7;
          color: #4a2a1d;
          transform: translateY(-3px);
          border-color: transparent;
        }

        .stat-item{
          background:var(--gradient-glass);
          border-radius:var(--radius-md);
          padding:2rem 2rem;
          border:1px solid var(--glass-border);
          box-shadow:var(--glass-shadow);
          text-align:center;
          transition:var(--transition);
          color:var(--cream-50);
