import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';
const skills = ['HTML', 'CSS', 'JavaScript', 'PHP', 'MySQL', 'Python', 'Bootstrap', 'Java', 'React', 'Vite'];

const roles = [
  'Software Engineer',
  'Full Stack',
  'Web Development',
  'Mobile Development',
  'Desktop Development'
];

export default function Home() {
  const [recentProjects, setRecentProjects] = useState([]);
  const [totalProject, setTotalProject] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);
  const [roleIndex, setRoleIndex] = useState(0);
  const cardRefs = useRef([]);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    fetch(`${API}/api/projects/recent`)
      .then((r) => r.json())
      .then(setRecentProjects)
      .catch(console.error);

    fetch(`${API}/api/projects/count`)
      .then((r) => r.json())
      .then((d) => setTotalProject(d.total))
      .catch(console.error);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setRoleIndex((prev) => (prev + 1) % roles.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoaded(true);
    }, 100);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (!isLoaded) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry, i) => {
          if (entry.isIntersecting) {
            setTimeout(() => {
              entry.target.style.opacity = '1';
              entry.target.style.transform = 'translateY(0)';
            }, i * 100);
          }
        });
      },
      { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }
    );

    cardRefs.current.forEach((el) => {
      if (el) {
        el.style.opacity = '0';
        el.style.transform = 'translateY(30px)';
        el.style.transition = 'all 0.7s cubic-bezier(0.34,1.56,0.64,1)';
        observer.observe(el);
      }
    });
    return () => observer.disconnect();
  }, [isLoaded, recentProjects]);

  return (
    <>
      <style>{`
        :root {
          --choco-900: #24140f;
          --choco-800: #321c14;
          --choco-700: #4a2a1d;
          --cream-50: #fff8ed;
          --cream-100: #f6ead7;
          --cream-200: #ead5b8;
          --caramel: #c98545;
          --pink-soft: #f5c6d0;
          --pink-mid: #e8a0b0;
          --leopard-spot: #8a6b4a;
          --leopard-light: #d4b896;
          --gradient-main: linear-gradient(135deg, #4a2a1d 0%, #8a4b2a 54%, #c98545 100%);
          --gradient-glass: linear-gradient(145deg, rgba(50, 28, 20, 0.94), rgba(36, 20, 15, 0.88));
          --text-dark: #2b1811;
          --text-gray: #7f624d;
          --glass-bg: rgba(50, 28, 20, 0.90);
          --glass-border: rgba(255, 248, 237, 0.16);
          --glass-shadow: 0 24px 80px rgba(36, 20, 15, 0.18), inset 0 1px 0 rgba(255, 248, 237, 0.12);
          --radius-lg: 28px;
          --radius-md: 18px;
          --transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background:
            radial-gradient(circle at 0% 50%, rgba(201, 133, 69, 0.16), transparent 45%),
            radial-gradient(circle at 100% 50%, rgba(74, 42, 29, 0.12), transparent 45%),
            linear-gradient(180deg, var(--cream-50) 0%, var(--cream-100) 100%);
          color: var(--choco-900);
          min-height: 100vh;
          position: relative;
          overflow-x: hidden;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background:
            radial-gradient(ellipse at 18% 18%, rgba(36, 20, 15, 0.28) 0 7px, rgba(201, 133, 69, 0.26) 8px 15px, transparent 16px),
            radial-gradient(ellipse at 72% 28%, rgba(74, 42, 29, 0.24) 0 6px, rgba(201, 133, 69, 0.22) 7px 13px, transparent 14px),
            radial-gradient(ellipse at 36% 74%, rgba(36, 20, 15, 0.22) 0 5px, rgba(201, 133, 69, 0.20) 6px 12px, transparent 13px);
          background-size: 145px 130px, 175px 155px, 190px 170px;
          opacity: 0.70;
          mask-image:
            radial-gradient(circle at 0 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 0 100%, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 100%, #000 0 20%, transparent 36%);
          -webkit-mask-image:
            radial-gradient(circle at 0 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 0, #000 0 20%, transparent 36%),
            radial-gradient(circle at 0 100%, #000 0 20%, transparent 36%),
            radial-gradient(circle at 100% 100%, #000 0 20%, transparent 36%);
        }

        @keyframes floatOrb {
          0%,100%{transform:translate(0,0)scale(1)}
          25%{transform:translate(40px,-50px)scale(1.15)}
          50%{transform:translate(-25px,25px)scale(0.85)}
          75%{transform:translate(50px,30px)scale(1.1)}
        }
        @keyframes gradientMove {
          0%,100%{background-position:0% 50%}
          50%{background-position:100% 50%}
        }
        @keyframes shimmer {
          0%,100%{background-position:0% 50%}
          50%{background-position:100% 50%}
        }
        @keyframes pulseBadge {
          0%,100%{transform:scale(1)}
          50%{transform:scale(1.03)}
        }
        @keyframes fadeInUp {
          from{opacity:0;transform:translateY(50px)scale(0.96)}
          to{opacity:1;transform:translateY(0)scale(1)}
        }
        @keyframes heartBeat {
          0%,100%{transform:scale(1)}
          14%{transform:scale(1.3)}
          28%{transform:scale(1)}
          42%{transform:scale(1.3)}
          56%{transform:scale(1)}
        }
        @keyframes roleChange {
          0%{opacity:0;transform:translateY(-10px)}
          10%{opacity:1;transform:translateY(0)}
          90%{opacity:1;transform:translateY(0)}
          100%{opacity:0;transform:translateY(10px)}
        }

        @keyframes heroShimmer {
          0% { background-position: -200% center; }
          100% { background-position: 200% center; }
        }

        @keyframes heroGlowPulse {
          0%, 100% { box-shadow: 0 24px 80px rgba(36,20,15,0.18), inset 0 1px 0 rgba(255,248,237,0.12); }
          50% { box-shadow: 0 24px 100px rgba(201,133,69,0.15), 0 24px 80px rgba(36,20,15,0.18), inset 0 1px 0 rgba(255,248,237,0.16); }
        }

        .bg-orb{position:absolute;border-radius:50%;filter:blur(100px);animation:floatOrb 25s ease-in-out infinite}
        .bg-orb:nth-child(1){width:600px;height:600px;background:#c98545;top:-250px;right:-150px;opacity:0.12}
        .bg-orb:nth-child(2){width:450px;height:450px;background:#8a4b2a;bottom:-150px;left:-120px;animation-delay:-8s;opacity:0.15}
        .bg-orb:nth-child(3){width:350px;height:350px;background:#4a2a1d;top:50%;left:40%;animation-delay:-16s;opacity:0.10}

        .main-content{position:relative;z-index:1;padding-top:100px}

        .hero-section{padding:0.5rem 0 2rem;animation:fadeInUp 1s cubic-bezier(0.34,1.56,0.64,1)}

        /* ================================================================ */
        /* ========== HERO GLASS ========================================== */
        /* ================================================================ */
        .hero-glass{
          background: var(--gradient-glass);
          border-radius: var(--radius-lg);
          border: 1px solid var(--glass-border);
          box-shadow: var(--glass-shadow);
          padding: 0;
          position: relative;
          overflow: hidden;
          color: var(--cream-50);
          animation: heroGlowPulse 4s ease-in-out infinite;
          transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
          display: flex;
          min-height: 400px;
        }

        .hero-glass::before {
          content: '';
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          background: linear-gradient(
            105deg,
            transparent 20%,
            rgba(255,248,237,0.04) 40%,
            rgba(255,248,237,0.08) 50%,
            rgba(255,248,237,0.04) 60%,
            transparent 80%
          );
          background-size: 300% 100%;
          z-index: 0;
          pointer-events: none;
          animation: heroShimmer 6s ease-in-out infinite;
          border-radius: var(--radius-lg);
        }

        .hero-glass::after {
          content: '';
          position: absolute;
          inset: -1px;
          border-radius: var(--radius-lg);
          padding: 1px;
          background: linear-gradient(
            135deg,
            transparent 20%,
            rgba(201,133,69,0.12),
            rgba(245,198,208,0.08),
            rgba(201,133,69,0.12),
            transparent 80%
          );
          background-size: 300% 300%;
          -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
          -webkit-mask-composite: xor;
          mask-composite: exclude;
          animation: heroShimmer 4s linear infinite;
          z-index: 0;
          pointer-events: none;
        }

        .hero-glass:hover {
          box-shadow: 0 24px 100px rgba(36,20,15,0.22), 0 0 60px rgba(201,133,69,0.06);
          border-color: rgba(255,248,237,0.20);
        }

        .hero-glass > * {
          position: relative;
          z-index: 1;
        }

        /* ================================================================ */
        /* ========== SPLIT LEFT: FOTO + LEOPARD ========================== */
        /* ================================================================ */
        .hero-split-left {
          flex: 0 0 42%;
          position: relative;
          overflow: hidden;
          min-height: 400px;
          background: linear-gradient(160deg, #f6ead7, #fff8ed);
          clip-path: polygon(
            0% 0%,
            100% 0%,
            92% 10%,
            88% 20%,
            85% 35%,
            88% 50%,
            85% 65%,
            88% 80%,
            92% 90%,
            100% 100%,
            0% 100%
          );
          border-radius: var(--radius-lg) 0 0 var(--radius-lg);
        }

        /* ===== LEOPARD PATTERN ===== */
        .hero-split-left .leopard-bg {
          position: absolute;
          inset: 0;
          z-index: 0;
          pointer-events: none;
        }

        .hero-split-left .leopard-bg .spot {
          position: absolute;
          border-radius: 50%;
          background: rgba(138,107,74,0.20);
        }

        .hero-split-left .leopard-bg .s1 { width: 50px; height: 60px; top: 10%; left: 8%; transform: rotate(20deg); }
        .hero-split-left .leopard-bg .s2 { width: 35px; height: 40px; top: 30%; right: 15%; transform: rotate(-15deg); background: rgba(212,184,150,0.20); }
        .hero-split-left .leopard-bg .s3 { width: 60px; height: 70px; bottom: 15%; left: 6%; transform: rotate(35deg); }
        .hero-split-left .leopard-bg .s4 { width: 25px; height: 30px; top: 55%; right: 10%; transform: rotate(-30deg); background: rgba(212,184,150,0.15); }
        .hero-split-left .leopard-bg .s5 { width: 40px; height: 45px; bottom: 40%; right: 25%; transform: rotate(10deg); }
        .hero-split-left .leopard-bg .s6 { width: 20px; height: 25px; top: 70%; left: 20%; transform: rotate(45deg); background: rgba(212,184,150,0.12); }
        .hero-split-left .leopard-bg .s7 { width: 30px; height: 35px; top: 8%; left: 45%; transform: rotate(-10deg); }
        .hero-split-left .leopard-bg .s8 { width: 45px; height: 50px; bottom: 8%; right: 20%; transform: rotate(25deg); background: rgba(212,184,150,0.12); }
        .hero-split-left .leopard-bg .s9 { width: 18px; height: 22px; top: 45%; left: 35%; transform: rotate(15deg); }
        .hero-split-left .leopard-bg .s10 { width: 50px; height: 55px; top: 20%; left: 65%; transform: rotate(-20deg); background: rgba(138,107,74,0.10); }

        /* ===== FOTO PROFIL - TIDAK KEPOTONG ===== */
        .hero-split-left .profile-photo {
          position: absolute;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%);
          width: 70%;
          height: 85%;
          z-index: 1;
          object-fit: contain;
          object-position: center;
          filter: drop-shadow(0 8px 32px rgba(36,20,15,0.15));
          transition: all 0.5s ease;
          border-radius: 20px;
          background: transparent;
        }

        .hero-glass:hover .profile-photo {
          transform: translate(-50%, -50%) scale(1.02);
        }

        /* ===== SHIMMER OVERLAY ===== */
        .hero-split-left .photo-shimmer {
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          background: linear-gradient(
            105deg,
            transparent 30%,
            rgba(255,248,237,0.04) 45%,
            rgba(255,248,237,0.08) 50%,
            rgba(255,248,237,0.04) 55%,
            transparent 70%
          );
          background-size: 300% 100%;
